// A tool the verification system MAY choose for TS type-safety metrics.
// It is not a codified verdict — the runner decides per metric whether this is
// the right instrument and records why. Pure AST parse: reads, never executes,
// so it is safe to point at an untrusted clone.
//
// Counts, over a given scope, using the TypeScript compiler's own parser:
//   any      : `any` keyword type nodes (AnyKeyword)
//   as       : real cast nodes (AsExpression), excluding `as const`; import
//              aliases are NOT AsExpression, so they are correctly ignored
//   nonnull  : non-null assertion nodes (NonNullExpression)  e.g. foo!.bar
//   tsignore : @ts-ignore / @ts-expect-error directive comments
//
// Resolution of the `typescript` lib (first that works):
//   repo/node_modules/typescript  ->  $TS_LIB  ->  /tmp/tsverify/...  ->  'typescript'
const path = require('path'), fs = require('fs');
const repo = process.argv[2];
const scope = (process.argv[3] || 'api/src,web/src,shared/src').split(',');
const includeTests = process.argv.includes('--include-tests');

function loadTs() {
  const tries = [
    path.join(repo, 'node_modules', 'typescript'),
    process.env.TS_LIB,
    '/tmp/tsverify/node_modules/typescript',
    'typescript',
  ].filter(Boolean);
  for (const t of tries) { try { return require(t); } catch (e) {} }
  throw new Error('typescript not found; set TS_LIB');
}
const ts = loadTs();

const isTest = (f) => /(__tests__|__mocks__|\.test\.|\.spec\.|[\\/]tests[\\/]|[\\/]e2e[\\/])/.test(f);
const files = [];
for (const s of scope) {
  const root = path.join(repo, s);
  if (!fs.existsSync(root)) continue;
  (function walk(d) {
    for (const e of fs.readdirSync(d, { withFileTypes: true })) {
      const p = path.join(d, e.name);
      if (e.isDirectory()) { if (e.name === 'node_modules' || e.name === 'dist') continue; walk(p); }
      else if (/\.tsx?$/.test(e.name) && (includeTests || !isTest(p))) files.push(p);
    }
  })(root);
}

const c = { any: 0, as: 0, nonnull: 0, tsignore: 0 };
for (const f of files) {
  const code = fs.readFileSync(f, 'utf8');
  const src = ts.createSourceFile(f, code, ts.ScriptTarget.Latest, true,
    f.endsWith('.tsx') ? ts.ScriptKind.TSX : ts.ScriptKind.TS);
  c.tsignore += (code.match(/@ts-(ignore|expect-error)/g) || []).length;
  (function visit(n) {
    if (n.kind === ts.SyntaxKind.AnyKeyword) c.any++;
    else if (ts.isAsExpression(n)) {
      const t = n.type;
      const isConst = t && ts.isTypeReferenceNode(t) && t.typeName && t.typeName.escapedText === 'const';
      if (!isConst) c.as++;
    } else if (ts.isNonNullExpression(n)) c.nonnull++;
    ts.forEachChild(n, visit);
  })(src);
}

console.log(JSON.stringify({
  tool: 'typescript-ast',
  ts_version: ts.version,
  scope, include_tests: includeTests,
  files: files.length,
  counts: c,
  total: c.any + c.as + c.nonnull,
}));

#!/usr/bin/env node
// Tool to run eslint and return a formatted table of violation types and their counts
import { spawnSync } from "child_process";
import { resolve } from "path";

const root = resolve(import.meta.dirname, "..");
const eslintBin = resolve(root, "node_modules/.bin/eslint");

const result = spawnSync(
  eslintBin,
  ["api/src", "web/src", "shared/src", "--format", "json"],
  { cwd: root, encoding: "utf8", maxBuffer: 64 * 1024 * 1024 }
);

const results = JSON.parse(result.stdout);

const PACKAGES = ["api/src", "web/src", "shared/src"];

function emptyTally() {
  return { any: 0, assertion: 0, nonNull: 0, tsIgnore: 0, tsExpect: 0 };
}

const byPackage = Object.fromEntries(PACKAGES.map((p) => [p, emptyTally()]));
const totals = emptyTally();
const fileCounts = [];

for (const file of results) {
  const pkg = PACKAGES.find((p) => file.filePath.includes("/" + p + "/")) ?? null;
  const tally = pkg ? byPackage[pkg] : null;
  let fileTotal = 0;

  for (const msg of file.messages) {
    const r = msg.ruleId ?? "";
    const m = msg.message ?? "";

    let bucket = null;
    if (r === "@typescript-eslint/no-explicit-any") bucket = "any";
    else if (r === "@typescript-eslint/consistent-type-assertions") bucket = "assertion";
    else if (r === "@typescript-eslint/no-non-null-assertion") bucket = "nonNull";
    else if (r === "@typescript-eslint/ban-ts-comment") {
      if (m.includes("@ts-ignore")) bucket = "tsIgnore";
      else if (m.includes("@ts-expect-error")) bucket = "tsExpect";
    }

    if (bucket) {
      if (tally) tally[bucket]++;
      totals[bucket]++;
      fileTotal++;
    }
  }

  if (fileTotal > 0) {
    fileCounts.push({ file: file.filePath.replace(root + "/", ""), count: fileTotal });
  }
}

fileCounts.sort((a, b) => b.count - a.count);

const grandTotal = Object.values(totals).reduce((a, b) => a + b, 0);

function pkgTotal(t) {
  return t.any + t.assertion + t.nonNull + t.tsIgnore + t.tsExpect;
}

function pct(n) {
  return grandTotal === 0 ? "0%" : `${Math.round((n / grandTotal) * 100)}%`;
}

const col = (s, w) => String(s).padStart(w);

console.log("\n=== TypeScript Violation Summary (by package) ===");
console.log(
  `${"Package".padEnd(14)} ${"any".padStart(5)} ${"as".padStart(6)} ${"!".padStart(6)} ${"@ts-i".padStart(6)} ${"@ts-e".padStart(6)} ${"Total".padStart(7)} ${"Share".padStart(6)}`
);
console.log("─".repeat(62));
for (const pkg of PACKAGES) {
  const t = byPackage[pkg];
  const tot = pkgTotal(t);
  console.log(
    `${pkg.padEnd(14)} ${col(t.any,5)} ${col(t.assertion,6)} ${col(t.nonNull,6)} ${col(t.tsIgnore,6)} ${col(t.tsExpect,6)} ${col(tot,7)} ${col(pct(tot),6)}`
  );
}
console.log("─".repeat(62));
console.log(
  `${"Total".padEnd(14)} ${col(totals.any,5)} ${col(totals.assertion,6)} ${col(totals.nonNull,6)} ${col(totals.tsIgnore,6)} ${col(totals.tsExpect,6)} ${col(grandTotal,7)}`
);

console.log("\n=== Violation-Dense Files (sorted) ===");
for (const f of fileCounts) {
  console.log(`${f.count.toString().padStart(4)}  ${f.file}`);
}

